import React, { useEffect, useState, useRef } from "react";
import mapboxgl from "mapbox-gl";

mapboxgl.accessToken = "YOUR_MAPBOX_ACCESS_TOKEN";

const BusMap = () => {
  const mapContainer = useRef(null);
  const map = useRef(null);

  const [buses, setBuses] = useState([]);
  const [showGhost, setShowGhost] = useState(true);
  const [showActive, setShowActive] = useState(true);

  useEffect(() => {
    map.current = new mapboxgl.Map({
      container: mapContainer.current,
      style: "mapbox://styles/mapbox/streets-v11",
      center: [-73.935242, 40.73061], // NYC center
      zoom: 11,
    });

    // Add zoom buttons
    map.current.addControl(new mapboxgl.NavigationControl(), "top-left");
  }, []);

  useEffect(() => {
    const ws = new WebSocket("ws://127.0.0.1:8000/ws/buses");

    ws.onmessage = (event) => {
      const data = JSON.parse(event.data);
      setBuses(data.buses);
    };

    ws.onclose = () => console.log("WebSocket closed");
    ws.onerror = (err) => console.error("WebSocket error:", err);

    return () => ws.close();
  }, []);

  useEffect(() => {
    if (!map.current) return;

    // Remove old markers
    document.querySelectorAll(".bus-marker").forEach((el) => el.remove());

    // Add markers
    buses.forEach((bus) => {
      if ((bus.status === "ghost" && showGhost) || (bus.status === "active" && showActive)) {
        const el = document.createElement("div");
        el.className = "bus-marker";
        el.style.width = "12px";
        el.style.height = "12px";
        el.style.borderRadius = "50%";
        el.style.backgroundColor = bus.status === "ghost" ? "red" : "green";
        el.title = `${bus.id} (${bus.feed})`;

        new mapboxgl.Marker(el)
          .setLngLat([bus.lon, bus.lat])
          .addTo(map.current);
      }
    });
  }, [buses, showGhost, showActive]);

  return (
    <div style={{ position: "relative", height: "100vh", width: "100%" }}>
      <div ref={mapContainer} style={{ height: "100%", width: "100%" }} />

      {/* Filter */}
      <div
        style={{
          position: "absolute",
          top: "80px", // shifted down to avoid zoom buttons
          left: "10px",
          background: "white",
          padding: "10px",
          borderRadius: "6px",
          zIndex: 1,
          boxShadow: "0 0 5px rgba(0,0,0,0.3)",
        }}
      >
        <div>
          <input
            type="checkbox"
            checked={showActive}
            onChange={() => setShowActive(!showActive)}
          />{" "}
          Show Active
        </div>
        <div>
          <input
            type="checkbox"
            checked={showGhost}
            onChange={() => setShowGhost(!showGhost)}
          />{" "}
          Show Ghost
        </div>
      </div>

      {/* Bus count */}
      <div
        style={{
          position: "absolute",
          bottom: "10px",
          left: "10px",
          background: "white",
          padding: "6px 10px",
          borderRadius: "6px",
          boxShadow: "0 0 5px rgba(0,0,0,0.3)",
        }}
      >
        Total Buses: {buses.length}
      </div>
    </div>
  );
};

export default BusMap;
